#!/usr/bin/env python3
"""TASK-3: Move BFS traversal downstream_tasks from workflow-cli/src/main.rs into workflow_core/src/state.rs as pub fn TaskSuccessors::downstream_of; update CLI to call through the library; move unit tests with it"""
import base64, json, subprocess, sys

TASK_ID = "TASK-3"
STEPS = json.loads('[{"before_b64": "ICAgIC8vLyBSZXR1cm5zIGB0cnVlYCBpZiB0aGUgc3VjY2Vzc29yIG1hcCBoYXMgbm8gZW50cmllcy4KICAgIHB1YiBmbiBpc19lbXB0eSgmc2VsZikgLT4gYm9vbCB7CiAgICAgICAgc2VsZi4wLmlzX2VtcHR5KCkKICAgIH0KfQ==", "after_b64": "", "target": "workflow_core/src/state.rs", "index": 0}, {"before_b64": "", "after_b64": "", "target": "workflow-cli/src/main.rs", "index": 1}, {"before_b64": "ICAgICAgICBTb21lKHN1Y2Nlc3NvcnMpID0+IHsKICAgICAgICAgICAgbGV0IGRvd25zdHJlYW0gPSBkb3duc3RyZWFtX3Rhc2tzKHRhc2tfaWRzLCBzdWNjZXNzb3JzKTs=", "after_b64": "ICAgICAgICBTb21lKHN1Y2Nlc3NvcnMpID0+IHsKICAgICAgICAgICAgbGV0IGRvd25zdHJlYW0gPSBzdWNjZXNzb3JzLmRvd25zdHJlYW1fb2YodGFza19pZHMpOw==", "target": "workflow-cli/src/main.rs", "index": 2}, {"before_b64": "ICAgICNbdGVzdF0KICAgIGZuIG9sZF9zdGF0ZV9maWxlX2Rlc2VyaWFsaXplc193aXRob3V0X3Rhc2tfc3VjY2Vzc29ycygpIHs=", "after_b64": "", "target": "workflow_core/src/state.rs", "index": 3}, {"before_b64": "", "after_b64": "fQ==", "target": "workflow-cli/src/main.rs", "index": 4}]')

for step in STEPS:
    before = base64.b64decode(step["before_b64"]).decode()
    after = base64.b64decode(step["after_b64"]).decode()
    target = step["target"]
    idx = step["index"]

    content = open(target).read()
    if before not in content:
        print(f"FAILED {TASK_ID} change {idx}: pattern not found in {target}", file=sys.stderr)
        print(f"Expected (first 200 chars): {repr(before[:200])}", file=sys.stderr)
        sys.exit(1)

    result = subprocess.run(
        ["sd", "-F", "-A", "-n", "1", before, after, target],
        capture_output=True, text=True,
    )
    if result.returncode != 0:
        print(f"FAILED {TASK_ID} change {idx}: sd error: {result.stderr}", file=sys.stderr)
        sys.exit(result.returncode)

    new_content = open(target).read()
    if after and after not in new_content:
        print(f"FAILED {TASK_ID} change {idx}: replacement not found after apply", file=sys.stderr)
        sys.exit(1)

    print(f"OK {TASK_ID} change {idx}: applied to {target}")

print(f"OK {TASK_ID}: all changes applied")
